import React from 'react';
import ReactDOM from 'react-dom';
import { BrowserRouter } from 'react-router-dom';
import App from './App';

ReactDOM.render(
  <React.StrictMode>
    <BrowserRouter>
      <App />
    </BrowserRouter>
  </React.StrictMode>,
  document.getElementById('root')
);

import React from 'react';
import { Routes, Route } from 'react-router-dom';
import Login from './pages/Login';
import Dashboard from './pages/Dashboard';
import TaskDetail from './pages/TaskDetail';
import WorkspaceSettings from './pages/WorkspaceSettings';
import ProtectedRoute from './components/ProtectedRoute';

const App: React.FC = () => {
  return (
    <div className='bg-gray-100 min-h-screen'>
      <Routes>
        <Route path='/login' element={<Login />} />
        <Route element={<ProtectedRoute />}>          
          <Route path='/' element={<Dashboard />} />
          <Route path='/tasks/:taskId' element={<TaskDetail />} />
          <Route path='/workspaces/:workspaceId/settings' element={<WorkspaceSettings />} />
        </Route>
      </Routes>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const Login: React.FC = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const response = await axios.post('/api/auth/login', { email, password });
      localStorage.setItem('token', response.data.token);
      navigate('/');
    } catch (error) {
      console.error('Login failed:', error);
    }
  };

  return (
    <div className='flex justify-center items-center h-screen'>
      <form onSubmit={handleSubmit} className='bg-white p-8 rounded shadow-md w-full max-w-sm'>
        <h2 className='text-2xl font-bold mb-6'>Login</h2>
        <div className='mb-4'>
          <label htmlFor='email' className='block text-gray-700 text-sm font-bold mb-2'>Email</label>
          <input type='email' id='email' value={email} onChange={(e) => setEmail(e.target.value)} className='shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 leading-tight focus:outline-none focus:shadow-outline' required />
        </div>
        <div className='mb-6'>
          <label htmlFor='password' className='block text-gray-700 text-sm font-bold mb-2'>Password</label>
          <input type='password' id='password' value={password} onChange={(e) => setPassword(e.target.value)} className='shadow appearance-none border rounded w-full py-2 px-3 text-gray-700 mb-3 leading-tight focus:outline-none focus:shadow-outline' required />
        </div>
        <button type='submit' className='bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded focus:outline-none focus:shadow-outline'>Sign In</button>
      </form>
    </div>
  );
};

export default Login;

import React, { useEffect, useState } from 'react';
import axios from 'axios';
import TaskCard from '../components/TaskCard';
import { useWebSocket } from '@react-websocket/client';

const Dashboard: React.FC = () => {
  const [tasks, setTasks] = useState([]);
  const [notifications, setNotifications] = useState([]);

  useEffect(() => {
    const fetchTasks = async () => {
      try {
        const response = await axios.get('/api/workspaces/1/tasks');
        setTasks(response.data);
      } catch (error) {
        console.error('Failed to fetch tasks:', error);
      }
    };
    fetchTasks();
  }, []);

  const { lastMessage } = useWebSocket('ws://localhost:8000/ws');

  useEffect(() => {
    if (lastMessage !== null) {
      setNotifications(prev => [...prev, JSON.parse(lastMessage.data)]);
    }
  }, [lastMessage]);

  return (
    <div className='p-4'>
      <h1 className='text-3xl font-bold mb-4'>Dashboard</h1>
      <div className='mb-4'>
        <h2 className='text-xl font-bold mb-2'>Notifications</h2>
        <ul>
          {notifications.map((notification, index) => (
            <li key={index} className='bg-white p-4 mb-2 rounded shadow-md'>{notification.message}</li>
          ))}
        </ul>
      </div>
      <div className='grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4'>
        {tasks.map(task => (
          <TaskCard key={task.id} task={task} />
        ))}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const TaskDetail: React.FC = () => {
  const { taskId } = useParams<{ taskId: string }>();
  const [task, setTask] = useState<any>(null);

  useEffect(() => {
    const fetchTask = async () => {
      try {
        const response = await axios.get(`/api/tasks/${taskId}`);
        setTask(response.data);
      } catch (error) {
        console.error('Failed to fetch task:', error);
      }
    };
    fetchTask();
  }, [taskId]);

  if (!task) return <div>Loading...</div>;

  return (
    <div className='p-4'>
      <h1 className='text-3xl font-bold mb-4'>Task Detail</h1>
      <div className='bg-white p-8 rounded shadow-md'>
        <h2 className='text-xl font-bold mb-2'>{task.title}</h2>
        <p className='text-gray-700 mb-4'>{task.description}</p>
        <p><strong>Status:</strong> {task.status}</p>
        <p><strong>Due Date:</strong> {new Date(task.dueDate).toLocaleDateString()}</p>
        <p><strong>Priority:</strong> {task.priority}</p>
      </div>
    </div>
  );
};

export default TaskDetail;

import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

const WorkspaceSettings: React.FC = () => {
  const { workspaceId } = useParams<{ workspaceId: string }>();
  const [workspace, setWorkspace] = useState<any>(null);

  useEffect(() => {
    const fetchWorkspace = async () => {
      try {
        const response = await axios.get(`/api/workspaces/${workspaceId}`);
        setWorkspace(response.data);
      } catch (error) {
        console.error('Failed to fetch workspace:', error);
      }
    };
    fetchWorkspace();
  }, [workspaceId]);

  if (!workspace) return <div>Loading...</div>;

  return (
    <div className='p-4'>
      <h1 className='text-3xl font-bold mb-4'>Workspace Settings</h1>
      <div className='bg-white p-8 rounded shadow-md'>
        <h2 className='text-xl font-bold mb-2'>{workspace.name}</h2>
        <p className='text-gray-700 mb-4'>{workspace.description}</p>
        <p><strong>Owner:</strong> {workspace.owner.email}</p>
        <p><strong>Members:</strong> {workspace.members.map((member: any) => member.email).join(', ')}</p>
      </div>
    </div>
  );
};

export default WorkspaceSettings;

import React from 'react';
import { Link } from 'react-router-dom';

interface Task {
  id: number;
  title: string;
  description: string;
  status: string;
  dueDate: string;
  priority: string;
}

const TaskCard: React.FC<{ task: Task }> = ({ task }) => {
  return (
    <Link to={`/tasks/${task.id}`} className='block bg-white p-4 rounded shadow-md hover:shadow-lg transition-shadow duration-300'>
      <h3 className='text-lg font-bold mb-2'>{task.title}</h3>
      <p className='text-gray-700 mb-2'>{task.description}</p>
      <p><strong>Status:</strong> {task.status}</p>
      <p><strong>Due Date:</strong> {new Date(task.dueDate).toLocaleDateString()}</p>
      <p><strong>Priority:</strong> {task.priority}</p>
    </Link>
  );
};

export default TaskCard;

import React from 'react';
import { Navigate, Outlet } from 'react-router-dom';

const ProtectedRoute: React.FC = () => {
  const isAuthenticated = !!localStorage.getItem('token');

  if (!isAuthenticated) {
    return <Navigate to='/login' replace />;
  }

  return <Outlet />;
};

export default ProtectedRoute;

